def caesar_encrypt(message, key):
    encrypted_message = ""
    for char in message:
        if char.isalpha():
            num = ord(char)
            num += key
            if char.isupper():
                if num > ord('Z'):
                    num -= 26
                elif num < ord('A'):
                    num += 26
            elif char.islower():
                if num > ord('z'):
                    num -= 26
                elif num < ord('a'):
                    num += 26
            encrypted_message += chr(num)
        else:
            encrypted_message += char
    return encrypted_message

def hex_to_decimal(num):
    decimal = 0
    for i in range(len(num)):
        if num[i] == 'A':
            decimal += 10 * (16 ** (len(num)-i-1))
        elif num[i] == 'B':
            decimal += 11 * (16 ** (len(num)-i-1))
        elif num[i] == 'C':
            decimal += 12 * (16 ** (len(num)-i-1))
        elif num[i] == 'D':
            decimal += 13 * (16 ** (len(num)-i-1))
        elif num[i] == 'E':
            decimal += 14 * (16 ** (len(num)-i-1))
        elif num[i] == 'F':
            decimal += 15 * (16 ** (len(num)-i-1))
        else:
            decimal += int(num[i]) * (16 ** (len(num)-i-1))
    return decimal

